n = int(input())
board = []
for i in range(n):
    board.append(list(input()))

count = 0
for i in range(n):
    for j in range(n):
        if board[i][j] == 'o':
            count += 1
            if i > 0 and board[i-1][j] == 'o':
                count -= 1
            if i < n-1 and board[i+1][j] == 'o':
                count -= 1
            if j > 0 and board[i][j-1] == 'o':
                count -= 1
            if j < n-1 and board[i][j+1] == 'o':
                count -= 1
if count == 0:
    print("YES")
else:
    print("NO")
